import json
import sys

def validate_config():
    """Validate that config.json exists and has required fields"""
    try:
        with open('config.json', 'r') as f:
            config = json.load(f)

        # Check required fields
        required_fields = ['pagasa_url', 'email_config', 'check_interval_seconds', 'notification_enabled']
        missing_fields = []

        for field in required_fields:
            if field not in config:
                missing_fields.append(field)

        if missing_fields:
            print(f"❌ Missing required fields in config.json: {missing_fields}")
            return False

        # Check email config
        email_config = config['email_config']
        email_required = ['smtp_server', 'smtp_port', 'sender_email', 'sender_password', 'recipient_email']
        missing_email = []

        for field in email_required:
            if field not in email_config:
                missing_email.append(field)

        if missing_email:
            print(f"❌ Missing required email fields: {missing_email}")
            return False

        print("✅ Configuration file is valid")
        return True

    except FileNotFoundError:
        print("❌ config.json file not found")
        return False
    except json.JSONDecodeError as e:
        print(f"❌ Invalid JSON in config.json: {e}")
        return False
    except Exception as e:
        print(f"❌ Error validating config: {e}")
        return False

if __name__ == "__main__":
    success = validate_config()
    sys.exit(0 if success else 1)

