import requests
import json
from datetime import datetime

# Simple status checker for PAGASA typhoon monitoring

def check_pagasa_status():
    """Check if PAGASA website is accessible"""
    try:
        headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        }
        response = requests.get('https://www.pagasa.dost.gov.ph/', headers=headers, timeout=10)

        if response.status_code == 200:
            print(f"✅ PAGASA website is accessible")
            print(f"   Status code: {response.status_code}")
            print(f"   Response time: {response.elapsed.total_seconds():.2f}s")

            # Check for typhoon-related content
            content = response.text.lower()
            keywords = ['typhoon', 'tropical cyclone', 'bulletin', 'storm']
            found_keywords = [kw for kw in keywords if kw in content]

            if found_keywords:
                print(f"   Typhoon keywords found: {', '.join(found_keywords)}")
            else:
                print("   No typhoon keywords found in homepage")

        else:
            print(f"❌ PAGASA website returned status code: {response.status_code}")

    except requests.exceptions.RequestException as e:
        print(f"❌ Error connecting to PAGASA website: {e}")

if __name__ == "__main__":
    print(f"PAGASA Status Check - {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 50)
    check_pagasa_status()

